import { createContext, useContext, useState, useEffect } from 'react';
import { NotificationContextType, NotificationProps } from '../contexts/Nofitication.context';
import { notify } from '../helpers/notification.helpers';

const NotificationContext = createContext<NotificationContextType | null>(null);

const useNotification = () => {
  const [notificationElem, setNotificationElem] = useState<HTMLElement | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const elem = document.querySelector('huel-notification');
    if (elem) setNotificationElem(elem);
  }, []);

  const triggerNotification = async (props: NotificationProps) => {
    try {
      if (!notificationElem) return;
      await notify(notificationElem, props);
    } catch (error) {
      setError(error.message);
    }
  };

  return { notificationElem, triggerNotification, error };
};

export default useNotification;
