Here's an example of an updated `BaseRepository` class in C# that allows you to find by a dynamic field:

```csharp
public interface IBaseRepository<T> where T : class
{
    Task<T> GetByIdAsync(Guid id);
    Task<IEnumerable<T>> GetAllAsync();
    Task<IEnumerable<T>> FindAsync(Expression<Func<T, bool>> expression);
    Task<T> FindFirstOrDefaultAsync(Expression<Func<T, bool>> expression);
}

public abstract class BaseRepository<T> : IBaseRepository<T> where T : class
{
    protected readonly DbContext _dbContext;

    protected BaseRepository(DbContext dbContext)
    {
        _dbContext = dbContext;
    }

    public virtual async Task<T> GetByIdAsync(Guid id)
    {
        return await _dbContext.Set<T>().FindAsync(id);
    }

    public virtual async Task<IEnumerable<T>> GetAllAsync()
    {
        return await _dbContext.Set<T>().ToListAsync();
    }

    public virtual async Task<IEnumerable<T>> FindAsync(Expression<Func<T, bool>> expression)
    {
        return await _dbContext.Set<T>().Where(expression).ToListAsync();
    }

    public virtual async Task<T> FindFirstOrDefaultAsync(Expression<Func<T, bool>> expression)
    {
        return await _dbContext.Set<T>().FirstOrDefaultAsync(expression);
    }
}

